import React from 'react';
import { useQuery } from '@tanstack/react-query';
import { Eye, Edit } from 'lucide-react';
import { columnsApi } from '../api/columns';
import { Report } from '../types';

interface DataTableProps {
  data: Report[];
  loading?: boolean;
  onEdit?: (report: Report) => void;
  onView?: (report: Report) => void;
}

const DataTable: React.FC<DataTableProps> = ({ data, loading = false, onEdit, onView }) => {
  const { data: columns = [], isLoading: columnsLoading } = useQuery({
    queryKey: ['columns'],
    queryFn: columnsApi.getColumns,
  });

  if (loading || columnsLoading) {
    return (
      <div className="bg-white rounded-lg border border-gray-200 overflow-hidden">
        <div className="animate-pulse">
          <div className="h-12 bg-gray-50 border-b border-gray-200"></div>
          {[...Array(5)].map((_, i) => (
            <div key={i} className="h-16 border-b border-gray-100"></div>
          ))}
        </div>
      </div>
    );
  }

  const fixedColumns = ['report_date', 'month_label'];
  const dynamicColumns = columns.filter(col => !fixedColumns.includes(col.key));

  const formatValue = (value: any) => {
    if (value === null || value === undefined) return '';
    if (typeof value === 'number') return value.toLocaleString();
    return value.toString();
  };

  const calculateSum = (columnKey: string) => {
    return data.reduce((sum, row) => {
      const value = row.data[columnKey];
      return sum + (typeof value === 'number' ? value : 0);
    }, 0);
  };

  const totalNumericSum = dynamicColumns.reduce((total, col) => {
    return total + calculateSum(col.key);
  }, 0);

  const avgPerDay = data.length > 0 ? totalNumericSum / data.length : 0;

  return (
    <div className="space-y-4">
      {/* Table */}
      <div className="bg-white rounded-lg border border-gray-200 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="min-w-full divide-y divide-gray-200">
            <thead className="bg-gray-50">
              <tr>
                <th className="sticky left-0 bg-gray-50 px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider border-r border-gray-200">
                  Date
                </th>
                <th className="sticky left-24 bg-gray-50 px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider border-r border-gray-200">
                  Month
                </th>
                {dynamicColumns.map(column => (
                  <th
                    key={column.key}
                    className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider"
                  >
                    {column.label}
                  </th>
                ))}
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Actions
                </th>
              </tr>
            </thead>
            <tbody className="bg-white divide-y divide-gray-200">
              {data.length === 0 ? (
                <tr>
                  <td
                    colSpan={fixedColumns.length + dynamicColumns.length + 1}
                    className="px-6 py-8 text-center text-gray-500"
                  >
                    No data available
                  </td>
                </tr>
              ) : (
                data.map((row, index) => (
                  <tr key={row.report_date} className={index % 2 === 0 ? 'bg-white' : 'bg-gray-50'}>
                    <td className="sticky left-0 bg-inherit px-6 py-4 whitespace-nowrap text-sm font-medium text-gray-900 border-r border-gray-200">
                      {row.report_date}
                    </td>
                    <td className="sticky left-24 bg-inherit px-6 py-4 whitespace-nowrap text-sm text-gray-600 border-r border-gray-200">
                      {row.month_label || '-'}
                    </td>
                    {dynamicColumns.map(column => (
                      <td
                        key={column.key}
                        className="px-6 py-4 whitespace-nowrap text-sm text-gray-900"
                      >
                        {formatValue(row.data[column.key])}
                      </td>
                    ))}
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                      <div className="flex space-x-2">
                        {onView && (
                          <button
                            onClick={() => onView(row)}
                            className="text-gray-400 hover:text-gray-600"
                            title="View"
                          >
                            <Eye className="w-4 h-4" />
                          </button>
                        )}
                        {onEdit && (
                          <button
                            onClick={() => onEdit(row)}
                            className="text-gray-400 hover:text-gray-600"
                            title="Edit"
                          >
                            <Edit className="w-4 h-4" />
                          </button>
                        )}
                      </div>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* Summary Footer */}
      <div className="bg-white rounded-lg border border-gray-200 p-4">
        <div className="grid grid-cols-3 gap-4 text-center">
          <div>
            <div className="text-2xl font-bold text-gray-900">{data.length}</div>
            <div className="text-sm text-gray-600">Total Records</div>
          </div>
          <div>
            <div className="text-2xl font-bold text-gray-900">{totalNumericSum.toLocaleString()}</div>
            <div className="text-sm text-gray-600">Total Sum</div>
          </div>
          <div>
            <div className="text-2xl font-bold text-gray-900">{avgPerDay.toFixed(1)}</div>
            <div className="text-sm text-gray-600">Avg Per Day</div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default DataTable;
